import numpy as np

def he_init(fan_in: int, fan_out: int, mode: str = 'fan_in', distribution: str = 'normal') -> np.ndarray:
    if mode == 'fan_in':
        n = fan_in
    elif mode == 'fan_out':
        n = fan_out
    else:
        raise ValueError(f"mode must be 'fan_in' or 'fan_out', got '{mode}'")

    if distribution == 'normal':
        std = np.sqrt(2.0 / n)
        return np.random.randn(fan_in, fan_out) * std
    elif distribution == 'uniform':
        limit = np.sqrt(6.0 / n)
        return np.random.uniform(-limit, limit, size=(fan_in, fan_out))
    else:
        raise ValueError(f"distribution must be 'normal' or 'uniform', got '{distribution}'")

def init_mlp_he(layer_sizes: list[int], distribution: str = 'normal') -> list[tuple]:
    params = []
    for i in range(len(layer_sizes) - 1):
        W = he_init(layer_sizes[i], layer_sizes[i + 1], mode='fan_in', distribution=distribution)
        b = np.zeros(layer_sizes[i + 1])
        params.append((W, b))
    return params

